package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithIgnoreEmptyLines() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat newFormat = format.withIgnoreEmptyLines();

        assertNotNull(newFormat, "The returned CSVFormat should not be null");
        assertTrue(newFormat.getIgnoreEmptyLines(), "The ignoreEmptyLines flag should be true");

        // Also test that original format is unchanged (immutable)
        assertFalse(format.getIgnoreEmptyLines(), "Original CSVFormat should remain unchanged");
    }
}
